def flatten_once(groups: Iterable[Iterable[int]]) -> list[int]:
    """Flatten exactly one level of nested iterables."""
    result = []
    for group in groups:
        if isinstance(group, (list, tuple)):
            result.extend(group)
        else:
            result.append(group)
    return result
